mapper.select:
SELECT a.*
FROM sys_organization a
         LEFT JOIN pr_data_grant b ON b.org_id = a.id AND b.company_id = #{companyId}
WHERE a.company_id = #{companyId}
  AND b.user_id = #{userId}
  AND a.level != '3'

SELECT COUNT(1)
FROM sys_organization
WHERE parent_id = #{id}
  AND company_id = #{companyId}

SELECT COUNT(1)
FROM pr_building
WHERE org_id = #{id}
  AND company_id = #{companyId}

SELECT COUNT(1)
FROM sys_user
WHERE dept_id = #{id}
  AND company_id = #{companyId}
